import{_ as t,o as n,c as i,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"7. Relationship To Previous Industrial Instruments And The","description":"","frontmatter":{"title":"7. Relationship To Previous Industrial Instruments And The","eba":"Allied Health Professionals 2021-2026","topics":["disputes","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/preliminary/7-relationship-to-previous-industrial-instruments-and-the.md","filePath":"ebas/allied-health/preliminary/7-relationship-to-previous-industrial-instruments-and-the.md"}'),a={name:"ebas/allied-health/preliminary/7-relationship-to-previous-industrial-instruments-and-the.md"};function r(o,e,l,h,d,p){return n(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="_7-relationship-to-previous-industrial-instruments-and-the" tabindex="-1">7. Relationship To Previous Industrial Instruments And The <a class="header-anchor" href="#_7-relationship-to-previous-industrial-instruments-and-the" aria-label="Permalink to &quot;7. Relationship To Previous Industrial Instruments And The&quot;">​</a></h1><p>NES</p><p><strong>7.1</strong> This is a comprehensive Agreement that operates to the exclusion of any award, workplace determination or other agreement which previously applied to Employees covered by this Agreement. However, any entitlement in the nature of an accrued entitlement to an Employee’s benefit which has accrued under any such previous industrial instrument will not be affected by the making of this Agreement.</p><p><strong>7.2</strong> Nothing in this Agreement will diminish any existing entitlement of any Employee covered by this Agreement, except where expressly varied by this Agreement.</p><p><strong>7.3</strong> A dispute or grievance that is being considered pursuant to <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of the 2020 Agreement at the time this Agreement commences operation may continue to be considered pursuant to <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of the 2020 Agreement.</p><p><strong>7.4</strong> This Agreement is not intended to exclude any part of the NES or to provide any entitlement which is detrimental to an Employee’s entitlement under the NES. For the avoidance of doubt, the NES prevails to the extent that any aspect of this Agreement would otherwise be detrimental to an Employee.</p>',6)])])}const c=t(a,[["render",r]]);export{m as __pageData,c as default};
